#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    const int notes[10] = {2000,500,200,100,50,20,10,5,2,1};
    while (T--) {
        int R;
        scanf("%d", &R);
        int cnt[10] = {0};
        int total = 0;
        for (int i = 0; i < 10; ++i) {
            if (R >= notes[i]) {
                cnt[i] = R / notes[i];
                total += cnt[i];
                R %= notes[i];
            }
        }
        printf("Minimum number of notes = %d\n", total);
        for (int i = 0; i < 10; ++i) {
            if (cnt[i] > 0) {
                printf("%d : %d\n", notes[i], cnt[i]);
            }
        }
    }
    return 0;
}

