const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
if (input.length === 0) process.exit(0);
let idx = 0;
const T = parseInt(input[idx++], 10);
const notes = [2000,500,200,100,50,20,10,5,2,1];
let output = [];
for (let t = 0; t < T; ++t) {
  let R = parseInt(input[idx++], 10);
  let total = 0;
  const used = [];
  for (const d of notes) {
    if (R >= d) {
      const c = Math.floor(R / d);
      used.push([d, c]);
      total += c;
      R %= d;
    }
  }
  output.push(`Minimum number of notes = ${total}`);
  for (const [d, c] of used) {
    output.push(`${d} : ${c}`);
  }
}
console.log(output.join('\n'));

